import React, { useState, useEffect, useRef, useMemo } from 'react';
import { MapPin, Plus, Trash2, X, Download, ChevronDown, ChevronUp, FileUp, FileDown, PlusCircle, Globe, Sliders, Settings, Edit3, Maximize } from 'lucide-react';
import { initializeApp } from 'firebase/app';
import { getDatabase, ref, onValue, push, set, remove, update } from 'firebase/database';
import * as htmlToImage from 'html-to-image';
import * as XLSX from 'xlsx';

const firebaseConfig = {
  apiKey: "AIzaSyCDbnnEkMGYu3HMJAb8kViLnJZfazJ1qms",
  authDomain: "rp2026-b5d0a11111.firebaseapp.com",
  databaseURL: "https://rp2026-b5d0a11111-default-rtdb.asia-southeast1.firebasedatabase.app",
  projectId: "rp2026-b5d0a11111",
  storageBucket: "rp2026-b5d0a11111.firebasestorage.app",
  messagingSenderId: "864135040245",
  appId: "1:864135040245:web:3e8e2d336ce379575d49bc"
};

const app = initializeApp(firebaseConfig);
const db = getDatabase(app);

const translations = {
  zh: { title: "巡展规划助手", select: "切换项目", new: "新建项目", clear: "清空站点", del: "删除项目", rename: "重命名", save: "保存", city: "城市", venue: "场馆", date: "日期", phase: "阶段", color: "颜色", speed: "动画速度", empty: "暂无数据", settings: "项目设置", fit: "适应视角" },
  en: { title: "Route Planner", select: "Switch Project", new: "New Project", clear: "Clear Stops", del: "Delete Project", rename: "Rename", save: "Save", city: "City", venue: "Venue", date: "Date", phase: "Phase", color: "Color", speed: "Speed", empty: "No Data", settings: "Project Settings", fit: "Fit Map" }
};

const initialStopState = { name: '', venue: '', phase: '1', color: '#3b82f6', startDate: new Date().toISOString().split('T')[0] };

function App() {
  const [lang, setLang] = useState('zh');
  const t = translations[lang];
  const [currentProject, setCurrentProject] = useState('默认规划图');
  const [projectMetadata, setProjectMetadata] = useState({});
  const [projects, setProjects] = useState(['默认规划图']);
  const [stops, setStops] = useState([]);
  const [isEditing, setIsEditing] = useState(false);
  const [showSettings, setShowSettings] = useState(false);
  const [newStop, setNewStop] = useState(initialStopState);
  const [speed, setSpeed] = useState(1.0);
  
  const mapRef = useRef(null);
  const clusterGroupRef = useRef(null);
  const mapContainerRef = useRef(null);
  const exportRef = useRef(null);
  const layersRef = useRef({ paths: [], arrows: [] });

  const groupedStops = useMemo(() => {
    const groups = {};
    const sorted = [...stops].sort((a, b) => a.order - b.order);
    sorted.forEach((stop) => {
      if (!groups[stop.phase]) groups[stop.phase] = { stops: [], color: stop.color };
      groups[stop.phase].stops.push({ ...stop, phaseIndex: groups[stop.phase].stops.length + 1 });
    });
    return groups;
  }, [stops]);

  useEffect(() => {
    onValue(ref(db, 'projects'), (snap) => {
      const data = snap.val();
      if (data) {
        // Filter out system IDs starting with '-'
        setProjects(Object.keys(data).filter(k => !k.startsWith('-') && typeof data[k] === 'object'));
        setProjectMetadata(data);
      }
    });
    return onValue(ref(db, `projects/${currentProject}/stops`), (snap) => {
      const data = snap.val();
      setStops(data ? Object.entries(data).map(([id, val]) => ({ id, ...val })).sort((a,b) => a.order - b.order) : []);
    });
  }, [currentProject]);

  useEffect(() => {
    if (!mapContainerRef.current || mapRef.current || !window.L) return;
    mapRef.current = window.L.map(mapContainerRef.current, { zoomControl: false, attributionControl: false }).setView([34.3416, 108.9398], 4);
    window.L.tileLayer('https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png').addTo(mapRef.current);
    clusterGroupRef.current = window.L.markerClusterGroup({ showCoverageOnHover: false }).addTo(mapRef.current);
  }, []);

  useEffect(() => {
    if (!mapRef.current || !clusterGroupRef.current) return;
    clusterGroupRef.current.clearLayers();
    layersRef.current.paths.forEach(p => p.remove());
    layersRef.current.arrows.forEach(a => a.remove());
    layersRef.current = { paths: [], arrows: [] };
    const animationIds = [];

    Object.values(groupedStops).forEach((group) => {
      const pathCoords = group.stops.map(s => [s.lat, s.lng]);
      const markers = group.stops.map(stop => {
        const icon = window.L.divIcon({
          className: 'no-bg', // REMOVES WHITE BACKGROUNDS
          html: `<div style="display: flex; align-items: center; gap: 10px;">
                    <div style="position: relative; width: 34px; height: 34px;">
                        <svg width="34" height="34" viewBox="0 0 24 24" fill="${stop.color}" stroke="white" stroke-width="2"><path d="M21 10c0 7-9 13-9 13s-9-6-9-13a9 9 0 0 1 18 0z"></path></svg>
                        <span style="position: absolute; top: 45%; left: 50%; transform: translate(-50%, -50%); color: white; font-size: 10px; font-weight: 900;">${stop.phaseIndex}</span>
                    </div>
                    <div style="background: white; padding: 4px 10px; border-radius: 8px; border: 1.5px solid ${stop.color}; box-shadow: 0 4px 6px rgba(0,0,0,0.1); display: flex; flex-direction: column;">
                        <span style="font-size: 8px; font-weight: 900; color: ${stop.color}; text-transform: uppercase;">${stop.startDate}</span>
                        <span style="font-size: 11px; font-weight: 700; color: #0f172a; white-space: nowrap;">${stop.venue || stop.name}</span>
                    </div>
                 </div>`,
          iconSize: [140, 34], iconAnchor: [17, 34]
        });
        const m = window.L.marker([stop.lat, stop.lng], { icon, phaseColor: stop.color });
        clusterGroupRef.current.addLayer(m);
        return m;
      });

      if (pathCoords.length > 1) {
        const poly = window.L.polyline(pathCoords, { color: group.color, weight: 4, dashArray: '10, 15', className: 'marching-ants' }).addTo(mapRef.current);
        layersRef.current.paths.push(poly);
        const arrowMarker = window.L.marker(pathCoords[0], { 
          icon: window.L.divIcon({ className: 'no-bg', html: `<div class="arrow-wrapper" style="color:${group.color}; opacity:0;"><svg width="24" height="24" viewBox="0 0 24 24"><path d="M12 2L22 22L12 18L2 22L12 2Z" fill="currentColor"/></svg></div>`, iconSize: [24,24], iconAnchor: [12,12] }) 
        }).addTo(mapRef.current);
        layersRef.current.arrows.push(arrowMarker);

        let totalD = 0; const segs = [];
        for(let i=0; i<pathCoords.length-1; i++) {
          const d = mapRef.current.distance(pathCoords[i], pathCoords[i+1]);
          segs.push({ s: pathCoords[i], e: pathCoords[i+1], d, c: totalD, sm: markers[i], em: markers[i+1] });
          totalD += d;
        }

        let start = null;
        const anim = (t) => {
          if(!start) start = t;
          let traveled = ((t - start) * (0.05 * speed)) % (totalD || 1);
          const seg = segs.find((s, idx) => traveled >= s.c && (idx === segs.length-1 || traveled < segs[idx+1].c));
          if(seg) {
            const p = (traveled - seg.c) / (seg.d || 1);
            const isVis = clusterGroupRef.current.getVisibleParent(seg.sm) === seg.sm && clusterGroupRef.current.getVisibleParent(seg.em) === seg.em;
            const ang = Math.atan2(mapRef.current.latLngToContainerPoint(seg.e).y - mapRef.current.latLngToContainerPoint(seg.s).y, mapRef.current.latLngToContainerPoint(seg.e).x - mapRef.current.latLngToContainerPoint(seg.s).x) * (180 / Math.PI) + 90;
            arrowMarker.setLatLng([seg.s[0] + (seg.e[0] - seg.s[0]) * p, seg.s[1] + (seg.e[1] - seg.s[1]) * p]);
            const el = arrowMarker.getElement();
            if(el) { const w = el.querySelector('.arrow-wrapper'); if(w){ w.style.opacity = isVis ? 1 : 0; w.style.transform = `rotate(${ang}deg)`; }}
          }
          animationIds.push(requestAnimationFrame(anim));
        };
        requestAnimationFrame(anim);
      }
    });
    return () => animationIds.forEach(id => cancelAnimationFrame(id));
  }, [groupedStops, speed]);

  const fitBounds = () => {
    if (stops.length > 0 && mapRef.current) {
      const bounds = stops.map(s => [s.lat, s.lng]);
      mapRef.current.fitBounds(bounds, { padding: [50, 50] });
    }
  };

  const moveStop = async (index, direction) => {
    const newStops = [...stops];
    const target = index + direction;
    if (target < 0 || target >= newStops.length) return;
    [newStops[index], newStops[target]] = [newStops[target], newStops[index]];
    const updates = {};
    newStops.forEach((s, i) => { updates[`projects/${currentProject}/stops/${s.id}/order`] = i; });
    await update(ref(db), updates);
  };

  return (
    <div ref={exportRef} className="flex flex-col h-screen bg-slate-50 overflow-hidden font-sans text-slate-900">
      <style>{`.no-bg { background: none !important; border: none !important; } .marching-ants { animation: dash 1s linear infinite; } @keyframes dash { to { stroke-dashoffset: -20; } }`}</style>
      
      {showSettings && (
        <div className="absolute right-0 top-0 bottom-0 w-80 bg-white shadow-2xl z-[100] border-l p-8 animate-in slide-in-from-right duration-300">
          <div className="flex justify-between items-center mb-10"><h3 className="text-xl font-black flex items-center gap-2"><Settings size={20}/> {t.settings}</h3><button onClick={()=>setShowSettings(false)} className="p-2 hover:bg-slate-100 rounded-full"><X size={20}/></button></div>
          <div className="space-y-6">
            <div className="p-4 bg-slate-50 rounded-xl space-y-4 border">
                <div className="flex items-center justify-between font-bold">
                    <span className="truncate max-w-[140px] uppercase">{currentProject}</span>
                    <button onClick={async () => {const n = window.prompt(t.rename, currentProject); if(n && n !== currentProject) { await set(ref(db, `projects/${n}`), projectMetadata[currentProject]); await remove(ref(db, `projects/${currentProject}`)); setCurrentProject(n); }}} className="p-2 text-blue-600 hover:bg-blue-50 rounded-lg"><Edit3 size={18} /></button>
                </div>
                <button onClick={() => { if(window.confirm(t.del)) { remove(ref(db, `projects/${currentProject}`)); setCurrentProject('默认规划图'); setShowSettings(false); }}} className="w-full flex items-center justify-center gap-2 py-3 bg-red-50 text-red-500 rounded-xl font-black text-xs hover:bg-red-100"><Trash2 size={16} />{t.del}</button>
            </div>
            <button onClick={fitBounds} className="w-full py-4 bg-blue-600 text-white rounded-xl font-black text-sm flex items-center justify-center gap-2 shadow-lg hover:scale-105 transition-all"><Maximize size={18} />{t.fit}</button>
            <button onClick={()=>{const n=window.prompt(t.new); if(n){set(ref(db,`projects/${n}`),{created:Date.now()}); setCurrentProject(n); setShowSettings(false);}}} className="w-full py-4 bg-slate-900 text-white rounded-xl font-black text-sm flex items-center justify-center gap-2 shadow-lg"><PlusCircle size={18} />{t.new}</button>
          </div>
        </div>
      )}

      <header className="flex items-center justify-between px-10 py-5 bg-white border-b shadow-sm z-10">
        <div className="flex items-center gap-6">
          <h1 className="text-xl font-black text-blue-600">RP.2026</h1>
          <div className="flex flex-col border-l pl-6">
            <span className="text-[10px] font-bold text-slate-400 uppercase">{t.select}</span>
            <select className="bg-transparent font-bold text-sm outline-none cursor-pointer" value={currentProject} onChange={(e)=>setCurrentProject(e.target.value)}>
                {projects.map(p => <option key={p} value={p}>{p}</option>)}
            </select>
          </div>
        </div>

        <div className="flex items-center gap-6">
          <div className="flex items-center gap-3 bg-slate-50 px-4 py-2 rounded-xl border">
             <Sliders size={16} className="text-slate-400" /><input type="range" min="0.1" max="10" step="0.1" value={speed} onChange={(e)=>setSpeed(parseFloat(e.target.value))} className="w-24 h-1.5 accent-blue-600 appearance-none bg-slate-200 rounded-full" />
             <span className="text-[10px] font-black text-blue-600">{Math.round(speed)}x</span>
          </div>
          <div className="flex items-center gap-2 border-l pl-6">
            <button onClick={()=>{if(window.confirm(t.clear)) remove(ref(db,`projects/${currentProject}/stops`));}} className="p-2 text-orange-400 hover:bg-orange-50 rounded-lg transition-colors" title={t.clear}><Trash2 size={20}/></button>
            <button onClick={()=>setShowSettings(true)} className="p-2 text-slate-400 hover:bg-slate-50 rounded-lg transition-colors"><Settings size={20}/></button>
          </div>
          <Globe size={18} className="text-slate-400" /><select className="text-xs font-black outline-none bg-transparent" value={lang} onChange={(e)=>setLang(e.target.value)}><option value="zh">ZH</option><option value="en">EN</option></select>
          <button onClick={()=>setIsEditing(true)} className="px-6 py-2.5 bg-blue-600 text-white rounded-2xl font-black text-sm shadow-lg hover:scale-105 transition-all">+ {t.addStop}</button>
        </div>
      </header>

      <main className="flex flex-1 p-6 gap-6 overflow-hidden">
        <div className="w-[420px] bg-white rounded-[40px] shadow-2xl border flex flex-col overflow-hidden">
          {isEditing ? (
            <div className="p-10 space-y-6 flex flex-col h-full animate-in slide-in-from-right duration-300">
              <div className="flex justify-between items-center"><h2 className="text-2xl font-black text-blue-600">{t.addStop}</h2><button onClick={()=>setIsEditing(false)} className="p-2 hover:bg-slate-100 rounded-full"><X/></button></div>
              <div className="space-y-4">
                  <input className="w-full p-4 bg-slate-50 rounded-2xl font-bold outline-none border focus:border-blue-500 uppercase" placeholder={t.city} value={newStop.name} onChange={e=>setNewStop({...newStop,name:e.target.value})} />
                  <input className="w-full p-4 bg-slate-50 rounded-2xl font-bold outline-none border focus:border-blue-500" placeholder={t.venue} value={newStop.venue} onChange={e=>setNewStop({...newStop,venue:e.target.value})} />
                  <div className="grid grid-cols-2 gap-4">
                    <div><label className="text-[10px] font-bold text-slate-400 ml-2 mb-1 block uppercase">{t.phase}</label><select className="w-full p-4 bg-slate-50 rounded-2xl font-bold border" value={newStop.phase} onChange={e=>{const ph=e.target.value; const ex=groupedStops[ph]; setNewStop({...newStop, phase:ph, color:ex?ex.color:newStop.color});}}>{[...Array(20)].map((_,i)=><option key={i+1} value={i+1}>{i+1}</option>)}</select></div>
                    <div><label className="text-[10px] font-bold text-slate-400 ml-2 mb-1 block uppercase">{t.color}</label><input type="color" disabled={!!groupedStops[newStop.phase]} className={`w-full h-14 p-1 bg-slate-50 rounded-2xl border ${!!groupedStops[newStop.phase] ? 'opacity-30 cursor-not-allowed' : 'cursor-pointer'}`} value={newStop.color} onChange={e=>setNewStop({...newStop,color:e.target.value})} /></div>
                  </div>
                  <input type="date" className="w-full p-4 bg-slate-50 rounded-2xl font-bold border" value={newStop.startDate} onChange={e=>setNewStop({...newStop, startDate: e.target.value})} />
              </div>
              <button onClick={async()=>{
                const r=await fetch(`https://nominatim.openstreetmap.org/search?format=json&q=${encodeURIComponent(newStop.name+' '+newStop.venue)}`);
                const g=await r.json();
                if(g[0]){ await set(push(ref(db,`projects/${currentProject}/stops`)),{...newStop,lat:parseFloat(g[0].lat),lng:parseFloat(g[0].lon),order:stops.length}); setIsEditing(false); setNewStop(initialStopState); }
              }} className="mt-auto w-full py-5 bg-blue-600 text-white rounded-3xl font-black uppercase shadow-xl hover:bg-blue-700 transition-all tracking-widest">{t.save}</button>
            </div>
          ) : (
            <div className="flex-1 overflow-y-auto p-8 space-y-8">
              {stops.length === 0 && <div className="h-full flex flex-col items-center justify-center opacity-20 mt-20"><MapPin size={64} /><p className="font-black tracking-widest uppercase">{t.empty}</p></div>}
              {Object.entries(groupedStops).map(([phase, data]) => (
                <div key={phase} className="space-y-4">
                  <div className="px-4 py-1.5 rounded-full inline-block font-black text-[10px] uppercase tracking-widest border" style={{ backgroundColor: `${data.color}15`, color: data.color }}>PHASE {phase}</div>
                  <div className="space-y-3">
                    {data.stops.map((s) => {
                       const originalIdx = stops.findIndex(stop => stop.id === s.id);
                       return (
                        <div key={s.id} className="p-5 bg-white rounded-3xl border flex items-center justify-between group hover:shadow-xl transition-all">
                          <div className="flex items-center gap-4 truncate">
                            <div className="w-6 h-6 rounded-full flex items-center justify-center text-[10px] font-black text-white" style={{ backgroundColor: s.color }}>{s.phaseIndex}</div>
                            <div className="truncate"><p className="font-black text-slate-700 text-sm uppercase tracking-tight">{s.name}</p><p className="text-[10px] text-slate-400 font-bold">{s.venue} · {s.startDate}</p></div>
                          </div>
                          <div className="flex items-center gap-1 opacity-0 group-hover:opacity-100 transition-all">
                            <button onClick={()=>moveStop(originalIdx, -1)} className="p-1 hover:bg-slate-100 rounded text-slate-400"><ChevronUp size={14}/></button>
                            <button onClick={()=>moveStop(originalIdx, 1)} className="p-1 hover:bg-slate-100 rounded text-slate-400"><ChevronDown size={14}/></button>
                            <button onClick={()=>remove(ref(db,`projects/${currentProject}/stops/${s.id}`))} className="p-1 text-red-400 hover:bg-red-50 rounded ml-2"><Trash2 size={14}/></button>
                          </div>
                        </div>
                    )})}
                  </div>
                </div>
              ))}
            </div>
          )}
        </div>
        <div className="flex-1 bg-white rounded-[56px] shadow-2xl overflow-hidden relative border-[12px] border-white">
          <div ref={mapContainerRef} className="h-full w-full" />
        </div>
      </main>
    </div>
  );
}

export default App;